import React, { useEffect, useRef } from "react";

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;
  const heroRef = useRef(null);

  useEffect(() => {
    const els = heroRef.current?.querySelectorAll(".anim");
    els?.forEach((el, i) => {
      el.style.opacity = "0";
      el.style.transform = "translateY(20px)";
      el.style.transition = `all 0.6s ease ${i * 0.1}s`;
      setTimeout(() => {
        el.style.opacity = "1";
        el.style.transform = "translateY(0)";
      }, 100);
    });
  }, []);

  const [firstName, ...rest] = name.split(" ");
  const lastName = rest.join(" ");

  return (
    <>
      <style>{`
        body {
          overflow-x: hidden;
          margin: 0;
          background: #05070d;
          color: white;
          font-family: sans-serif;
        }

        /* SECTION */
        .hero {
          min-height: 100vh;
          display: flex;
          justify-content: center;
          align-items: center;
          padding: clamp(60px, 8vw, 120px) 20px;
        }

        /* CONTAINER (🔥 FLUID WIDTH FIX) */
        .container {
          width: 100%;
          max-width: min(1400px, 92vw);
          margin: auto;
        }

        /* NAME */
        .name {
          font-size: clamp(2rem, 6vw, 6rem);
          font-weight: 800;
          line-height: 1.1;
          word-break: break-word;
        }

        .gradient {
          background: linear-gradient(90deg, #00e5ff, #7c3aed);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        /* TEXT */
        .sub {
          margin-top: 12px;
          color: #aaa;
          font-size: clamp(1rem, 1.5vw, 1.3rem);
        }

        .tag {
          margin-top: 10px;
          color: #888;
          max-width: 650px;
          line-height: 1.6;
        }

        /* BUTTONS */
        .btns {
          display: flex;
          gap: 12px;
          margin-top: 25px;
          flex-wrap: wrap;
        }

        .btn {
          padding: 12px 26px;
          border-radius: 999px;
          text-decoration: none;
          font-weight: 600;
          display: flex;
          justify-content: center;
          align-items: center;
          min-width: 160px;
          transition: 0.3s;
        }

        .primary {
          background: #00e5ff;
          color: black;
        }

        .primary:hover {
          transform: translateY(-3px);
          box-shadow: 0 10px 30px rgba(0,229,255,0.3);
        }

        .outline {
          border: 1px solid #444;
          color: white;
        }

        .outline:hover {
          border-color: #00e5ff;
          color: #00e5ff;
        }

        /* MOBILE BUTTON FIX */
        @media (max-width: 500px) {
          .btns {
            flex-direction: column;
          }
          .btn {
            width: 100%;
          }
        }

        /* STATS GRID (🔥 AUTO RESPONSIVE) */
        .stats {
          margin-top: clamp(40px, 5vw, 70px);
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
          gap: clamp(12px, 2vw, 25px);
        }

        /* CARD */
        .card {
          padding: clamp(20px, 2vw, 30px);
          border-radius: 18px;
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.08);
          text-align: center;
          transition: 0.3s;
        }

        .card:hover {
          transform: translateY(-6px) scale(1.02);
          box-shadow: 0 20px 50px rgba(0,229,255,0.15);
        }

        .value {
          font-size: clamp(1.5rem, 2.5vw, 3rem);
          font-weight: 800;
          color: #00e5ff;
        }

        .label {
          margin-top: 8px;
          font-size: 0.9rem;
          color: #aaa;
        }

        /* BIG SCREEN ENHANCEMENT (🔥 TV / 4K FIX) */
        @media (min-width: 1600px) {
          .name {
            font-size: clamp(4rem, 5vw, 7rem);
          }

          .sub {
            font-size: 1.5rem;
          }

          .tag {
            font-size: 1.2rem;
          }
        }

        /* ULTRA BIG (TV) */
        @media (min-width: 2000px) {
          .container {
            max-width: 1600px;
          }

          .stats {
            grid-template-columns: repeat(4, 1fr);
          }
        }
      `}</style>

      <section className="hero" ref={heroRef}>
        <div className="container">

          {/* NAME */}
          <h1 className="name anim">
            {firstName} <span className="gradient">{lastName}</span>
          </h1>

          {/* SUBTITLE */}
          <p className="sub anim">
            {title} · <span style={{ color: "#00e5ff" }}>{subtitle}</span>
          </p>

          {/* TAGLINE */}
          <p className="tag anim">{tagline}</p>

          {/* BUTTONS */}
          <div className="btns anim">
            <a href="mailto:your@email.com" className="btn primary">
              Get in Touch
            </a>

            <a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn outline"
            >
              LinkedIn
            </a>
          </div>

          {/* STATS */}
          <div className="stats">
            {stats.map((s, i) => (
              <div key={i} className="card">
                <div className="value">{s.value}</div>
                <div className="label">{s.label}</div>
              </div>
            ))}
          </div>

        </div>
      </section>
    </>
  );
}
